3205 // Under the assumption that I is unreachable, remove it and following
3206 // instructions. Changes are reported directly to MadeIRChange.
3207 void InstCombinerImpl::handleUnreachableFrom(
3208     Instruction *I, SmallVectorImpl<BasicBlock *> &Worklist) {
3209   BasicBlock *BB = I->getParent();
3210   for (Instruction &Inst : make_early_inc_range(
3211            make_range(std::next(BB->getTerminator()->getReverseIterator()),
3212                       std::next(I->getReverseIterator())))) {
3213     if (!Inst.use_empty() && !Inst.getType()->isTokenTy()) {
3214       replaceInstUsesWith(Inst, PoisonValue::get(Inst.getType()));
3215       MadeIRChange = true;
3216     }
3217     if (Inst.isEHPad() || Inst.getType()->isTokenTy())
3218       continue;
3219     // RemoveDIs: erase debug-info on this instruction manually.
3220     Inst.dropDbgValues();
3221     eraseInstFromFunction(Inst);
3222     MadeIRChange = true;
3223   }
3224 
3225   // RemoveDIs: to match behaviour in dbg.value mode, drop debug-info on
3226   // terminator too.
3227   BB->getTerminator()->dropDbgValues();
3228 
3229   // Handle potentially dead successors.
3230   for (BasicBlock *Succ : successors(BB))
3231     addDeadEdge(BB, Succ, Worklist);
