 27 static cl::opt<bool>
 28     VerifyKnownBits("instcombine-verify-known-bits",
 29                     cl::desc("Verify that computeKnownBits() and "
 30                              "SimplifyDemandedBits() are consistent"),
 31                     cl::Hidden, cl::init(false));
